using System;

[AttributeUsage(AttributeTargets.All)]
public class MethodAttr : Attribute
{
    public MethodAttr(string description) { Description = description; }
    public string Description { get; }
}

public interface IOrderService
{
    [MethodAttr("get order detail")]
    string GetOrder(int id);
}

[YS.Knife.ExposeApi(typeof(IOrderService), MethodAttributePatterns = new string[] { "MethodAttr" })]
public class TestController
{
}

