#pragma warning disable CS1591, CS1573
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
namespace 
{
    [ApiController]
    [Route("api/[controller]")]
    public class OrderController : ControllerBase
    {
        private readonly global::IOrderService iOrderService;
        public OrderController(global::IOrderService iOrderService)
        {
            this.iOrderService = iOrderService;
        }

        [Route("GetOrder/{id}")]
        [HttpGet]
        [global::MethodAttr("get order detail")]
        public string GetOrder([FromRoute] int id)
        {
            return this.iOrderService.GetOrder(id);                    
        }
    }
}
